110→    const handleClickNotif = handleCLickContent(navigate);
111→    const handleClickOpinionNotif = handleClickOpinion(navigate);
112→    const mutationReadNotif = useReadNotificationMutation(session);
113→
114→    const handleReadNotif = async(e, notification) => {
115→        e.stopPropagation();
116→        const source = notification?.source || 'journal';
117→        mutationReadNotif.mutate({notifId: notification.id, source})
118→
119→        if(source === 'opinion'){
120→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
121→        } else if(notification?.type === 'follow'){
122→            navigate(`/visitProfile?userId=${notification?.sender_id}`);
123→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
124→            // Navigate to the repost post (quote + embedded original)
125→            const repostId = notification.repost_journal_id;
126→            const encodedId = encodeURIComponent(repostId);
127→            navigate(`/home/post/${encodedId}`);
128→        } else {
129→            const parsedContent = ParseContent(notification?.journals?.content);
130→            handleClickNotif(
131→                e,
132→                notification?.journals?.content,
133→                parsedContent.wholeText,
134→                notification?.journals?.title,
135→                notification?.journals?.users.id,
136→                notification?.journals?.users?.name,
137→                notification?.journals?.users?.image_url,
138→                notification?.journals?.created_at,
139→                notification?.journal_id,
140→                notification?.hasLiked,
141→                notification?.journals?.comments[0].count,
142→                notification?.hasBookMarked,
143→                notification?.journals?.likes[0].count,
144→                notification?.journals?.bookmarks[0].count,
145→                notification?.journals?.users?.badge,
146→            )
147→        }
148→    }
149→
150→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
151→        queryKey: ['getNotifications', session?.access_token],
152→        queryFn: ({pageParam = null, queryKey}) => getNotifications(queryKey[1], pageParam, 5),
153→        getNextPageParam: (lastpage) =>{
154→            if(lastpage?.hasMore){
155→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
156→                return new Date(lastNotification.created_at).toISOString();
157→
158→            }
159→            return undefined;
160→        },
161→        enabled: !!session?.access_token,
162→        refetchOnWindowFocus: false,
163→        staleTime: 1000 * 60 * 2
164→    })
165→
166→    useEffect(() =>{
167→        if(scrollToTop.current && !isLoading){
168→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
169→        }
170→    }, [isLoading])
171→
172→    useEffect(() =>{
173→        if(hasNextPage && !isFetchingNextPage && inView){
174→            // console.log(hasNextPage)
175→            fetchNextPage();
176→        }
177→    }, [hasNextPage, isFetchingNextPage, inView, fetchNextPage])
178→
179→    const notifications = data?.pages?.flatMap((page) => page?.data) || [];
180→
181→    useEffect(() =>{
