251→                                <div className="notification-icon">
252→                                    <span style={{ fontSize: '26px', lineHeight: 1 }}>{getReactionEmoji(notification?.reaction_type) || '❤️'}</span>
253→                                </div>
254→                            ) : (
255→                                iconArray.map((icon, index) => (
256→                                    <div className="notification-icon" key={index}>
257→                                        {icon.type === displayType ? icon.icon : null}
258→                                    </div>
259→                                ))
260→                            )}
261→                        </div>
262→
263→                        <div className="notification-contents-container">
264→
265→                            <div className="notification-sender-user-metadata">
266→                                <div className="notification-sender-user-metadata-child">
267→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
268→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
269→                                    </div>
270→
271→                                    <div className="notif-sender-name-container">
272→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
273→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
274→                                        <p className="notif-type">{FormatNotificationType(displayType, notification?.reaction_type)}</p>
275→                                    </div>
276→
277→                                    <div className="notification-date-container">
278→                                        <p className="notification-date">{formatPostDate(notification?.created_at)}</p>
279→                                    </div>
280→                                </div>
281→                                <div className="notification-settings">
282→                                    {settingsId === notification.id && (
283→                                        <AnimatePresence>
284→                                        <motion.div
285→                                        initial={{opacity: 0, scale: 0}}
286→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
287→                                        exit={{ opacity: 0, scale: 0,
288→                                            transition: {
289→                                            duration: 0.2,
290→                                            ease: "easeOut"
291→                                            }
292→                                        }}
293→                                        ref={modalRef}
294→                                        className="settings-container">
295→
296→                                            <div onClick={(e) => handleClickDeleteNotification(e, notification?.id, notification?.source)} className="delete-notification">
